import{_ as a,o as i,c as e,ai as n}from"./chunks/framework.CsYGeNYI.js";const k=JSON.parse('{"title":"macOS 签名","description":"","frontmatter":{"read_when":["构建或签名 Mac 调试构建"],"summary":"打包脚本生成的 macOS 调试构建的签名步骤","title":"macOS 签名","x-i18n":{"generated_at":"2026-02-01T21:33:15Z","model":"claude-opus-4-5","provider":"pi","source_hash":"403b92f9a0ecdb7cb42ec097c684b7a696be3696d6eece747314a4dc90d8797e","source_path":"platforms/mac/signing.md","workflow":15}},"headers":[],"relativePath":"zh-CN/platforms/mac/signing.md","filePath":"zh-CN/platforms/mac/signing.md","lastUpdated":1771906665000}'),p={name:"zh-CN/platforms/mac/signing.md"};function l(t,s,c,o,h,r){return i(),e("div",null,[...s[0]||(s[0]=[n(`<h1 id="mac-签名-调试构建" tabindex="-1"><a class="header-anchor" href="#mac-签名-调试构建">#</a> Mac 签名（调试构建）</h1><p>此应用通常从 <a href="https://github.com/NJX-njx/opensoul/blob/main/scripts/package-mac-app.sh" target="_blank" rel="noreferrer"><code>scripts/package-mac-app.sh</code></a> 构建，该脚本目前会：</p><ul><li>设置稳定的调试 Bundle 标识符：<code>ai.opensoul.mac.debug</code></li><li>使用该 Bundle ID 写入 Info.plist（可通过 <code>BUNDLE_ID=...</code> 覆盖）</li><li>调用 <a href="https://github.com/NJX-njx/opensoul/blob/main/scripts/codesign-mac-app.sh" target="_blank" rel="noreferrer"><code>scripts/codesign-mac-app.sh</code></a> 对主二进制文件和应用包进行签名，使 macOS 将每次重新构建视为相同的已签名包，并保留 TCC 权限（通知、辅助功能、屏幕录制、麦克风、语音）。要获得稳定的权限，请使用真实签名身份；临时签名是可选的且不稳定（参阅 <a href="/docs/platforms/mac/permissions">macOS 权限</a>）。</li><li>默认使用 <code>CODESIGN_TIMESTAMP=auto</code>；为 Developer ID 签名启用受信任的时间戳。设置 <code>CODESIGN_TIMESTAMP=off</code> 可跳过时间戳（离线调试构建）。</li><li>将构建元数据注入 Info.plist：<code>OpenSoulBuildTimestamp</code>（UTC）和 <code>OpenSoulGitCommit</code>（短哈希），以便&quot;关于&quot;面板可以显示构建信息、git 信息和调试/发布渠道。</li><li><strong>打包需要 Node 22+</strong>：脚本会运行 TS 构建和 Control UI 构建。</li><li>从环境变量中读取 <code>SIGN_IDENTITY</code>。将 <code>export SIGN_IDENTITY=&quot;Apple Development: Your Name (TEAMID)&quot;</code>（或你的 Developer ID Application 证书）添加到 shell 配置文件中，以始终使用你的证书签名。临时签名需要通过 <code>ALLOW_ADHOC_SIGNING=1</code> 或 <code>SIGN_IDENTITY=&quot;-&quot;</code> 显式启用（不建议用于权限测试）。</li><li>签名后运行 Team ID 审计，如果应用包内的任何 Mach-O 文件由不同的 Team ID 签名则会失败。设置 <code>SKIP_TEAM_ID_CHECK=1</code> 可跳过此检查。</li></ul><h2 id="用法" tabindex="-1"><a class="header-anchor" href="#用法">#</a> 用法</h2><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 从仓库根目录</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">scripts/package-mac-app.sh</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">               # 自动选择身份；未找到时报错</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">SIGN_IDENTITY</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;Developer ID Application: Your Name&quot;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> scripts/package-mac-app.sh</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">   # 真实证书</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">ALLOW_ADHOC_SIGNING</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">1</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> scripts/package-mac-app.sh</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">    # 临时签名（权限不会持久化）</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">SIGN_IDENTITY</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;-&quot;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> scripts/package-mac-app.sh</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">        # 显式临时签名（同样的限制）</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">DISABLE_LIBRARY_VALIDATION</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">1</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> scripts/package-mac-app.sh</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">   # 仅限开发的 Sparkle Team ID 不匹配解决方案</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br></div></div><h3 id="临时签名注意事项" tabindex="-1"><a class="header-anchor" href="#临时签名注意事项">#</a> 临时签名注意事项</h3><p>使用 <code>SIGN_IDENTITY=&quot;-&quot;</code>（临时签名）签名时，脚本会自动禁用<strong>强化运行时</strong>（<code>--options runtime</code>）。这是为了防止应用在尝试加载不共享相同 Team ID 的嵌入式框架（如 Sparkle）时崩溃。临时签名还会破坏 TCC 权限持久化；参阅 <a href="/docs/platforms/mac/permissions">macOS 权限</a> 了解恢复步骤。</p><h2 id="关于面板的构建元数据" tabindex="-1"><a class="header-anchor" href="#关于面板的构建元数据">#</a> 关于面板的构建元数据</h2><p><code>package-mac-app.sh</code> 会在包中标记以下信息：</p><ul><li><code>OpenSoulBuildTimestamp</code>：打包时的 ISO8601 UTC 时间</li><li><code>OpenSoulGitCommit</code>：短 git 哈希（不可用时为 <code>unknown</code>）</li></ul><p>&quot;关于&quot;选项卡读取这些键以显示版本、构建日期、git 提交以及是否为调试构建（通过 <code>#if DEBUG</code>）。代码更改后运行打包程序以刷新这些值。</p><h2 id="原因" tabindex="-1"><a class="header-anchor" href="#原因">#</a> 原因</h2><p>TCC 权限与 Bundle 标识符<em>和</em>代码签名绑定。使用不断变化的 UUID 的未签名调试构建会导致 macOS 在每次重新构建后忘记授权。对二进制文件进行签名（默认临时签名）并保持固定的 Bundle ID/路径（<code>dist/OpenSoul.app</code>）可以在构建之间保留授权，与 VibeTunnel 的方案一致。</p>`,13)])])}const m=a(p,[["render",l]]);export{k as __pageData,m as default};
